const user = $('Filter Urgent Tasks').first().json;

// Task reminder for agent prompt
const taskAgentNote = (user.taskContext && user.taskContext.length > 0) 
  ? ' IMPORTANT: You MUST include a Tasks section immediately after the header — see TASK CONTEXT in your system instructions. Do not skip it.'
  : '';


const assistantName = user.assistant_name || 'Aria';
const assistantEmoji = user.assistant_emoji || ':robot_face:';
const assistantPersona = user.assistant_persona || 'direct, action-oriented, and conversational';
const repName = user.repName || (user.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || 'Rep';
const timezone = user.timezone || 'America/Los_Angeles';
const currentDate = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const timeStr = new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: timezone });

const oppTable = user.oppTable || '(No opportunity data available)';
const oppCount = user.userOppCount || 0;
const totalOppCount = user.totalOppCount || oppCount;
const digestScope = user.digestScope || 'my_deals';
const scopeLabel = user.scopeLabel || (repName + "'s OPEN OPPORTUNITIES");
const dateWindowEnd = user.dateWindowEnd || '';
const theme = user.theme || 'full_pipeline';
const themeLabel = user.themeLabel || 'Brief';
const themeNote = user.themeNote || '';
const focus         = user.focus || 'revenue';

const dayLabel = currentDate.split(',')[0];
const emojiClean = assistantEmoji.replace(/:/g, '');

// For person: scope — extract the target's display name from scopeLabel
const isPersonScope = digestScope.startsWith('person:');
const subjectName = isPersonScope
  ? scopeLabel.replace("'s OPEN OPPORTUNITIES", '').trim()
  : repName;

// === Shared Block Kit formatting rules ===
const blockKitRules = `OUTPUT FORMAT — CRITICAL:
Respond with ONLY a valid JSON object. Your ENTIRE response must be the JSON object and nothing else. No prose before or after. No explanation. No markdown code fences (no backticks). No "let me" or "here is" preamble. Start your response with { and end with }.

Your response must have exactly this shape:
{
  "notification_text": "string — one sentence, shown in push notifications",
  "blocks": [ array of valid Slack Block Kit blocks ]
}

BLOCK KIT STRUCTURE RULES:
- Use a "header" block for the message title (plain_text only, emoji: true)
- Use "section" blocks with "mrkdwn" text for all body content
- Use "divider" blocks between major sections (maximum 2 per message)
- Use "section" with "fields" for two-column data (engagement scores, metrics)
  - MAXIMUM 10 fields per section block (Slack API hard limit)
  - If you have more than 10 data points, split into multiple section blocks
- Use "context" block at the bottom for timestamp and data source
- Maximum 50 blocks per message

MRKDWN RULES (inside all text fields):
- Bold: *text* — single asterisks only
- Line break: \\n
- Blank line: \\n\\n
- Top-level bullets: use the • character (e.g. • Main point)
- Sub-bullets under a numbered item or heading: indent with 4 spaces before the bullet (e.g.     • Sub-point)
- This creates visual hierarchy — numbered deals at top level, details indented beneath
- NO ## headers — use *bold text* on its own line instead
- NO **double asterisks**
- NO standard markdown links [text](url) — use <https://url|text>
- NO dash bullets (-)

EMOJI STATUS INDICATORS — use these consistently:
🚀 Acceleration / strong momentum
⚠️ Risk pattern detected
💎 Hidden upside opportunity
🔴 Stalled / critical risk
✅ Healthy / on track
📈 Engagement rising
📉 Engagement falling
➡️ Engagement stable
🔥 High engagement (80+)

CRITICAL PRIORITIZATION RULE:
- Always prioritize deals closing in the NEXT 60 DAYS over deals closing later, regardless of deal size
- Today's date context is in the footer — use it to calculate proximity
- A $500K deal closing in 3 weeks matters more RIGHT NOW than a $3M deal closing in 8 months
- For deals closing 60+ days out, only mention them if they need immediate action (e.g., stalled engagement, missing exec sponsor)
- When listing "Top" deals, sort by close date proximity first, then by amount within the same time horizon`;

// === Focus-specific context injected into the system prompt ===
function getFocusContext(focus) {
  if (focus === 'retention') {
    return `FOCUS — RETENTION:
Your briefing covers only renewal and existing customer opportunities. New logo deals are excluded.
Prioritise: renewal health, time-to-renewal, expansion potential, customer engagement trends, churn risk.
Actions should be customer-success oriented: QBR scheduling, exec sponsor engagement, product adoption nudges, risk escalation.
Do NOT suggest new outreach tactics or prospecting actions.`;
  }
  if (focus === 'technical') {
    return `FOCUS — TECHNICAL:
You are briefing through an SE/solutions lens. Highlight POC status, technical blockers, and integration complexity.
Prioritise: deals in evaluation or validation stages, technical win/loss indicators, stakeholder technical depth.
Actions should be SE-oriented: POC milestones, technical champion engagement, competitive technical positioning.`;
  }
  if (focus === 'executive') {
    return `FOCUS — EXECUTIVE:
Deliver a high-altitude strategic view. Skip deal-level minutiae — focus on portfolio health, forecast risk, and org-level patterns.
Prioritise: total ARR at risk, big-bet deals, cross-functional signals, pipeline coverage.
Actions should be executive: sponsorship asks, resource allocation, forecast decisions.`;
  }
  // revenue (default) — no extra constraints
  return `FOCUS — REVENUE:
Prioritise new logo acquisition, net new ARR, and close-date velocity. Highlight deals with near-term close potential.
Actions should drive pipeline forward: next meeting, proposal, executive alignment, competitive positioning.`;
}

// === Role context by scope (data + identity) ===
function buildRoleContext(scope) {
  const mcpRules = `CRITICAL DATA RULES:
- ALWAYS include the EXACT dollar amount from the Amount column for every deal mentioned. Format as $X.XM or $XXK. Never say "Large deal" or "$X" — use the real number.
- ALWAYS make deal names clickable links using the PAI ID (People.ai Internal ID) column: <https://app.people.ai/opportunity/PAIID|Deal Name> (replace PAIID with the PAI ID value from the table)
- If Amount is empty, say "$TBD" — never omit the amount field

Do NOT use MCP to search for or list opportunities — they are already provided above.

DEEP LINKS — make each deal name a clickable link using the People.ai internal ID (peopleAiId column):
<https://app.people.ai/opportunity/PEOPLEAIID|Deal Name Here> (replace PEOPLEAIID with the peopleAiId value and Deal Name with the actual deal name)
Do NOT add a separate "View in People.ai" line — the deal name itself is the link.
Example: <https://app.people.ai/opportunity/5479658708|HPE AI Forensics Pilot>
If the peopleAiId is empty, omit the link and just use plain bold text for the deal name.

You DO have access to People.ai MCP tools. Use them ONLY for:
- Revenue stories and engagement analysis on specific deals
- Recent activity details (emails, meetings, calls) on key accounts
- Engagement score trends and changes`;

  if (scope === 'my_deals') {
    return `You are ${assistantName}, a personal sales assistant for ${repName}. You work exclusively for them and know their pipeline intimately.

Your personality: ${assistantPersona}

Today is ${currentDate}. ${repName} is in ${timezone}.

━━━ ${scopeLabel} (${oppCount} deals) ━━━
${themeNote ? '\n' + themeNote + '\n' : ''}
${oppTable}

${mcpRules}`;

  } else if (scope === 'team_deals') {
    return `You are ${assistantName}, a sales management assistant for ${repName}. You help them lead their team and stay ahead of pipeline risks.

Your personality: ${assistantPersona}

Today is ${currentDate}. ${repName} is in ${timezone}.

━━━ ${scopeLabel} (${oppCount} deals closing through ${dateWindowEnd}) ━━━
${themeNote ? '\n' + themeNote + '\n' : ''}
${oppTable}

${mcpRules}`;

  } else if (scope.startsWith('person:')) {
    return `You are ${assistantName}, a personal sales assistant for ${repName}. They have asked you to review ${subjectName}'s pipeline.

Your personality: ${assistantPersona}

Today is ${currentDate}. ${repName} is in ${timezone}.

━━━ ${scopeLabel} (${oppCount} deals) ━━━
${themeNote ? '\n' + themeNote + '\n' : ''}
${oppTable}

${mcpRules}

IMPORTANT — PERSON SCOPE:
- This brief is about *${subjectName}'s* pipeline, not ${repName}'s.
- Address ${repName} as the reader (e.g. "Here's Susan's pipeline for you to review...").
- Wherever the briefing structure says "your deals" or "your pipeline", treat that as "${subjectName}'s deals" / "${subjectName}'s pipeline".
- Never say "${repName}, your pipeline..." — say "${subjectName} has X deals..." or "Here's ${subjectName}'s pipeline...".`;

  } else {
    return `You are ${assistantName}, an executive sales intelligence assistant for ${repName}. You provide pipeline visibility and strategic signals at the leadership level.

Your personality: ${assistantPersona}

Today is ${currentDate}. ${repName} is in ${timezone}.

━━━ ${scopeLabel} ━━━
${themeNote ? '\n' + themeNote + '\n' : ''}
${oppTable}

${mcpRules}`;
  }
}

// === Scope-aware footer (includes scope label and theme for transparency) ===
function footer(scope) {
  const themeNames = {
    full_pipeline:     'Full Pipeline',
    engagement_shifts: 'Engagement Shifts',
    at_risk:           'At-Risk Focus',
    momentum:          'Momentum',
    week_review:       'Week Review'
  };
  const themeDisplay = themeNames[theme] || theme;

  let base;
  if (scope === 'team_deals')    base = 'Backstory team intelligence';
  else if (scope === 'top_pipeline') base = 'Backstory executive intelligence';
  else                           base = 'Backstory intelligence';

  return `${base} • ${currentDate} • ${timeStr} PT • ${scopeLabel} • ${themeDisplay}`;
}

// === Theme-specific briefing structure and agent prompt ===
function buildThemePrompts(theme, scope) {
  // person: scope uses IC-style structure
  const effectiveScope = scope.startsWith('person:') ? 'my_deals' : scope;
  const scopeTitle = effectiveScope === 'team_deals' ? ' Team' : effectiveScope === 'top_pipeline' ? ' Pipeline' : '';

  // ── EXEC COMPRESSED FORMAT (3+ deals) ──
  if (effectiveScope === 'top_pipeline' && oppCount >= 3) {
    const themeConfigs = {
      full_pipeline:      { label: 'Pipeline Brief',    section3: 'Top 3 Deals',       section4: 'This Week' },
      engagement_shifts:  { label: 'Engagement Shifts', section3: 'Top 3 Movers',      section4: 'Watch This Week' },
      at_risk:            { label: 'At-Risk Deals',     section3: 'Top 3 Risks',        section4: 'Fix It This Week' },
      momentum:           { label: 'Momentum',          section3: 'Top 3 Accelerators', section4: 'Keep the Momentum' },
      week_review:        { label: 'Week in Review',    section3: 'Top 3 Moves',        section4: 'Next Week' }
    };
    const tc = themeConfigs[theme] || themeConfigs['full_pipeline'];
    return {
      briefingStructure: `Write a compressed executive briefing — 60-second read, under 150 words (not counting header/footer). Use ${assistantPersona} personality ONLY in the opening sentence and the closing sentence. All other text is direct and factual.

BLOCK KIT STRUCTURE for this compressed exec format:
1. header block — "${emojiClean} ${dayLabel} ${tc.label} — ${assistantName}"
2. section block — 1 sentence in ${assistantPersona} voice with the single most important signal
3. section block — label only: "*${tc.section3}*"
4. One section block PER DEAL (exactly 3 deals), each formatted as:
   "*<https://app.people.ai/opportunity/PAIID|Deal Name>* — $Amount | [close date + key context]\\n    Action sentence — the most critical thing right now"
   The 4-space indent on the action line creates visual separation under each deal name.
   Do NOT combine multiple deals into one block.
5. section block — label only: "*${tc.section4}*"
6. section block — numbered list, 3 items (use \\n between items). For each item link the deal name: *<https://app.people.ai/opportunity/PAIID|Deal Name>* — one action sentence
7. section block — 1 sentence in ${assistantPersona} voice as sign-off
8. context block — "${footer(scope)}"

STRICT RULES:
- Exactly 3 deal blocks in item 4. Pick the most important 3.
- Personality ONLY in items 2 and 7
- No empty sections — omit any section with nothing to report
- No sub-bullets within deal entries — action line only`,
      agentPrompt: `Generate a compressed executive ${tc.label} briefing for ${repName}. ${oppCount} deals are pre-loaded — do NOT use MCP to search for opportunities. Focus on the top 3 most important deals only. Keep under 150 words (excluding header/footer). Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
    };
  }

  // ── FULL PIPELINE (Monday) ──
  if (theme === 'full_pipeline') {
    if (effectiveScope === 'my_deals') {
      return {
        briefingStructure: `Write a 60-second morning briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} Brief — ${assistantName}"
2. The Lead (1-2 sentences) — the single most important thing today
3. Today's Priorities (2-4 items) — specific actions with account names and reasons, use emoji status indicators
4. Pipeline Pulse — two-column engagement score grid using section fields
5. One Thing I'm Watching — one forward-looking observation
6. Context footer — "${footer(scope)}"`,

        agentPrompt: `Generate a pipeline briefing covering ${subjectName}'s ${oppCount} open opportunities for ${repName} to review. The opportunities are already loaded in your system prompt — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to investigate revenue stories and engagement patterns on the top 3-5 most important deals (highest amount, closest close date, or biggest engagement changes). Look for recent activity, meeting patterns, and risk signals.

Then write the briefing as a Block Kit JSON object following the format in your system instructions. Remember: output ONLY the JSON object, nothing else.` + taskAgentNote
      };
    } else if (effectiveScope === 'team_deals') {
      return {
        briefingStructure: `Write a 90-second team pipeline briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} Team Brief — ${assistantName}"
2. Team Pulse (2-3 sentences) — overall pipeline health: total pipeline value, deals closing this quarter and next, biggest risks
3. Reps Who Need Attention (2-3 items) — which reps have deals at risk, declining engagement, or upcoming close dates with no recent activity
4. Top Coaching Moments — 1-2 deals where manager intervention could change the outcome
5. Team Pipeline Snapshot — two-column grid: rep name + key metric
6. One Signal to Watch — a forward-looking team-level pattern
7. Context footer — "${footer(scope)}"`,

        agentPrompt: `Generate the team pipeline briefing for ${repName} (sales manager). Their team's ${oppCount} open deals closing through ${dateWindowEnd} are already loaded — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to investigate team engagement patterns: identify reps with declining engagement, spot coaching opportunities, and find deals where manager intervention could help. Focus on 3-5 highest-risk or highest-value deals.

Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
      };
    } else {
      return {
        briefingStructure: `Write a 90-second executive pipeline briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} Pipeline Brief — ${assistantName}"
2. Pipeline at a Glance (2-3 sentences) — total pipeline value, deal count, weighted forecast, deals closing this month
3. Top Deals to Watch (3-4 items) — highest-value or highest-risk deals with status
4. Forecast Signals — deal acceleration/stalling patterns, close date movements
5. Key Numbers — two-column grid: metric name + value
6. Strategic Signal — one forward-looking observation
7. Context footer — "${footer(scope)}"`,

        agentPrompt: `Generate the executive pipeline briefing for ${repName}. Top ${oppCount} deals by amount closing through ${dateWindowEnd} are loaded (${totalOppCount} total org-wide) — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to analyze pipeline health on the top 3-5 largest deals: velocity, engagement trends, risk signals, forecast-impacting patterns.

Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
      };
    }
  }

  // ── ENGAGEMENT SHIFTS (Tuesday) ──
  if (theme === 'engagement_shifts') {
    const scopeWho = effectiveScope === 'my_deals' ? (isPersonScope ? subjectName + "'s deals" : 'your deals') : effectiveScope === 'team_deals' ? "your team's deals" : 'deals across the organization';

    return {
      briefingStructure: `Write a 60-second engagement shift briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} Engagement Shifts${scopeTitle} — ${assistantName}"
2. The Shift (1-2 sentences) — summarize the biggest engagement movements across ${scopeWho}
3. Going Hot (2-3 deals) — deals with the highest engagement scores or most recent activity. What's driving the engagement? Use 📈 🔥 indicators.
4. Going Cold (2-3 deals) — deals with low or declining engagement, accounts going quiet. Use 📉 🔴 indicators.${effectiveScope !== 'my_deals' ? '\n5. Rep Activity Pulse — which reps are most/least active this week (two-column grid)' : '\n5. Activity Snapshot — two-column grid of engagement scores by deal'}
6. One Pattern — one insight about what's driving engagement up or down
7. Context footer — "${footer(scope)}"`,

      agentPrompt: `Generate an engagement shifts briefing for ${repName}. ${oppCount} deals are loaded — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to investigate engagement patterns: pull engagement score histories, recent activity timelines, and meeting/email cadence on the 3-5 deals with the most notable engagement movement (both positive and negative). Look for accounts going dark and accounts heating up.

Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
    };
  }

  // ── AT-RISK DEALS (Wednesday) ──
  if (theme === 'at_risk') {
    const scopeWho = effectiveScope === 'my_deals' ? (isPersonScope ? subjectName + "'s pipeline" : 'your pipeline') : effectiveScope === 'team_deals' ? "your team's pipeline" : 'the org pipeline';

    return {
      briefingStructure: `Write a 60-second at-risk deals briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} At-Risk Deals${scopeTitle} — ${assistantName}"
2. Risk Summary (1-2 sentences) — how many deals are showing risk signals in ${scopeWho}, total value at risk
3. Critical Risks (2-3 deals) — deals most likely to slip or stall. For each: what's wrong, how long it's been, and what to do about it. Use 🔴 ⚠️ indicators.
4. Going Dark (1-2 deals) — accounts with zero or minimal recent engagement. These need outreach now. Use 📉 indicators.${effectiveScope === 'team_deals' ? '\n5. Reps to Check In With — which reps have the most at-risk deals, who needs coaching or support' : effectiveScope === 'top_pipeline' ? '\n5. Forecast Impact — total dollar value at risk, potential slip from forecast' : '\n5. Risk vs. Healthy — two-column comparison grid'}
6. Fix-It Actions — 2-3 concrete next steps to address the biggest risks this week
7. Context footer — "${footer(scope)}"`,

      agentPrompt: `Generate an at-risk deals briefing for ${repName}. ${oppCount} deals flagged with risk signals are loaded — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to investigate the riskiest deals: look for missing activity, declining engagement trends, silent stakeholders, and deals where the close date is approaching without stage progression. Focus on the 3-5 highest-value deals at risk.

Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
    };
  }

  // ── MOMENTUM & WINS (Thursday) ──
  if (theme === 'momentum') {
    const scopeWho = effectiveScope === 'my_deals' ? (isPersonScope ? subjectName : 'your deals') : effectiveScope === 'team_deals' ? "your team" : 'the organization';

    return {
      briefingStructure: `Write a 60-second momentum briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} Momentum & Wins${scopeTitle} — ${assistantName}"
2. Momentum Check (1-2 sentences) — what's working across ${scopeWho} right now
3. Deals on Fire (2-3 deals) — highest engagement, most active, advancing fastest. What's fueling it? Use 🚀 🔥 ✅ indicators.
4. Hidden Upside (1-2 deals) — deals quietly outperforming expectations or with untapped expansion potential. Use 💎 indicators.${effectiveScope === 'team_deals' ? '\n5. Rep Wins — which reps are crushing it, what can others learn from their approach' : effectiveScope === 'top_pipeline' ? '\n5. Pipeline Acceleration — deals that advanced stages, new pipeline created, forecast upside' : '\n5. Engagement Leaders — two-column grid of your hottest deals by engagement'}
6. Keep It Going — 1-2 actions to maintain or amplify the momentum
7. Context footer — "${footer(scope)}"`,

      agentPrompt: `Generate a momentum and wins briefing for ${repName}. ${oppCount} deals are loaded (sorted by engagement) — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to validate positive signals: check deal velocity, recent meetings, rising engagement scores, and multithreading on the top 3-5 highest-engagement deals. Celebrate what's working and identify patterns to replicate.

Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
    };
  }

  // ── WEEK IN REVIEW (Friday) ──
  if (theme === 'week_review') {
    const scopeWho = effectiveScope === 'my_deals' ? (isPersonScope ? subjectName + "'s pipeline" : 'your pipeline') : effectiveScope === 'team_deals' ? "your team" : 'the organization';

    return {
      briefingStructure: `Write a 90-second week in review briefing following this structure:

1. Header — "${emojiClean} ${dayLabel} Week in Review${scopeTitle} — ${assistantName}"
2. This Week's Moves (2-3 sentences) — what changed in ${scopeWho} this week: deals that advanced, engagement shifts, notable activity
3. Wins & Progress (2-3 items) — deals that moved forward, positive engagement trends, meetings completed. Use ✅ 🚀 indicators.
4. Missed or Slipping (1-2 items) — deals that stalled or slipped this week, close dates pushed. Use ⚠️ 🔴 indicators.${effectiveScope === 'team_deals' ? '\n5. Team Scorecard — two-column grid: rep name + their week (active/quiet/strong)' : effectiveScope === 'top_pipeline' ? '\n5. Weekly Pipeline Delta — key numbers: pipeline added vs. closed, forecast movement' : '\n5. Week by the Numbers — two-column grid: key pipeline metrics this week vs. last'}
6. Next Week Preview — deals closing next week, meetings on the calendar, actions to set up for Monday
7. Context footer — "${footer(scope)}"`,

      agentPrompt: `Generate a week in review briefing for ${repName}. ${oppCount} deals are loaded — do NOT use MCP to search for opportunities.

Use People.ai MCP tools to compare this week's activity with previous patterns: look for deals that had new meetings, emails, or engagement changes this week. Identify what moved forward and what went quiet. Also check for meetings or close dates coming up next week.

Output ONLY the Block Kit JSON object, nothing else.` + taskAgentNote
    };
  }

  // Fallback
  return buildThemePrompts('full_pipeline', scope);
}

// === Build the prompts ===
const roleContext = buildRoleContext(digestScope);
const effectiveScope = isPersonScope ? 'my_deals' : digestScope;
const { briefingStructure, agentPrompt } = buildThemePrompts(theme, effectiveScope);

// For person-scope: MCP-first agent prompt since export API has no owner columns
let finalAgentPrompt = agentPrompt;
if (isPersonScope) {
  const targetEmail = digestScope.replace('person:', '');
  finalAgentPrompt = `Generate a ${themeLabel} briefing for ${repName} covering ${subjectName}'s open pipeline.

The pre-fetched opportunity table is empty for person-scope views because People.ai's export API does not filter by owner. Use the People.ai MCP tools to gather ${subjectName}'s deals directly.

Steps:
1. Use top_records or ask_sales_ai to find open opportunities owned by or associated with ${subjectName} (${targetEmail})
2. For each significant deal, use get_account_status or ask_sales_ai_about_account to get engagement level, last activity, and risk signals
3. Compile a ${themeLabel} briefing from what you find — focus on the theme: ${theme}

Address the briefing to ${repName} (the reader). Reference ${subjectName}'s pipeline, not ${repName}'s.
Output ONLY the Block Kit JSON object, nothing else.`;
}

const focusContext = getFocusContext(focus);

// === Task context (overdue + due this week) ===
const taskContext = user.taskContext || '';
const taskPromptSection = taskContext ? `
TASK CONTEXT:
${taskContext}

TASK SECTION INSTRUCTIONS:
The task context above tells you the total open tasks, how many are overdue, and how many are due today.

If total open tasks > 0, you MUST include a Tasks section IMMEDIATELY after the header block (before The Lead). Use this exact structure:

1. Add a divider block
2. Add a section block with the header line (all on ONE line). Build it based on counts:
   - Base: ":clipboard: *Open Tasks — N open*"
   - If overdue > 0, append: ", X overdue"
   - If due today > 0, append: ", Y due today"
   - Always append links: " · <https://glass.people.ai/sheet/514ff6d1-7e51-4bab-872e-b1f35ce13f5b|My Open Tasks> · <https://glass.people.ai/sheet/3be9132b-cf08-4f94-9164-651bb5804e51|My Completed> · <https://glass.people.ai/sheet/40ce97c4-0237-4afb-8d47-b10cf4792253|Last 30 Days>"
   - Examples: ":clipboard: *Open Tasks — 3 open, 2 overdue* · links", ":clipboard: *Open Tasks — 1 open* · links"
3. ONLY if there are overdue or due-today tasks in URGENT TASK DETAILS, add a section block listing each:
   - Use :red_circle: for overdue: ":red_circle: Task subject (Account) — N days overdue"
   - Use :warning: for due today: ":warning: Task subject (Account) — due today"
   - Show up to 5 items. If no urgent tasks, skip this block entirely.
4. Add a divider block after the task section.
5. Add a section block with ":zap: *Pipeline Brief*" to re-anchor the reader into pipeline content.
6. Then continue with The Lead.

If total open tasks = 0, do NOT include a Tasks section at all. Start directly with The Lead as normal.` : '';

const systemPrompt = (taskPromptSection ? taskPromptSection + '\n\n' : '') + roleContext + '\n\n' + focusContext + '\n\n' + briefingStructure + '\n\n' + blockKitRules;

return [{
  json: {
    userId: user.id,
    slackUserId: user.slack_user_id,
    assistantName,
    assistantEmoji,
    repName,
    digestScope,
    theme,
    themeLabel,
    systemPrompt,
    agentPrompt: finalAgentPrompt + taskAgentNote
  }
}];

const user = $('Filter User Opps').first().json;
const sendResult = $('Send Digest').first().json;
const digestContent = $('Digest Agent').first().json.output || 'Digest sent';
return [{
  json: {
    user_id: user.id,
    message_type: 'digest',
    channel: 'slack',
    direction: 'outbound',
    content: digestContent.substring(0, 5000),
    metadata: { slack_ts: sendResult.ts, slack_channel: sendResult.channel }
  }
}];

// Only process users who completed onboarding, have digest enabled, and have a real Slack ID
return $input.all().filter(item => 
  item.json.onboarding_state === 'complete' && 
  item.json.digest_enabled !== false &&
  item.json.slack_user_id && 
  !item.json.slack_user_id.startsWith('U_YOUR')
);

// Parse the agent's Block Kit JSON output
const agentOutput = $('Digest Agent').first().json.output;

let parsed;
try {
  // Try to extract JSON from the output — Claude sometimes wraps it in prose or code fences
  let cleaned = agentOutput;

  // Remove code fences
  cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

  // If it doesn't start with {, try to find JSON object in the text
  if (!cleaned.startsWith('{')) {
    const jsonMatch = cleaned.match(/\{[\s\S]*"blocks"[\s\S]*\}/);
    if (jsonMatch) {
      cleaned = jsonMatch[0];
    }
  }

  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: split raw output into chunks that fit Slack's 3000 char limit per block
  const maxLen = 2900;
  const text = agentOutput || 'Briefing generation failed.';
  const chunks = [];
  for (let i = 0; i < text.length; i += maxLen) {
    chunks.push(text.slice(i, i + maxLen));
  }

  const blocks = chunks.map((chunk, idx) => ({
    type: "section",
    text: { type: "mrkdwn", text: idx === 0 ? chunk : '...' + chunk }
  }));

  parsed = {
    notification_text: "Your briefing is ready",
    blocks
  };
}

// Enforce Slack limits
if (parsed.blocks) {
  parsed.blocks = parsed.blocks.map(block => {
    // Max 10 fields per section
    if (block.fields && block.fields.length > 10) {
      block.fields = block.fields.slice(0, 10);
    }
    // Max 3000 chars per text field in section blocks
    if (block.text && block.text.text && block.text.text.length > 3000) {
      block.text.text = block.text.text.slice(0, 2997) + '...';
    }
    // Max 3000 chars per field text
    if (block.fields) {
      block.fields = block.fields.map(f => {
        if (f.text && f.text.length > 2000) {
          f.text = f.text.slice(0, 1997) + '...';
        }
        return f;
      });
    }
    return block;
  });
  // Max 50 blocks
  if (parsed.blocks.length > 50) {
    parsed.blocks = parsed.blocks.slice(0, 50);
  }
}

return [{
  json: {
    notificationText: parsed.notification_text || "Your briefing",
    blocks: JSON.stringify(parsed.blocks),
    rawContent: agentOutput
  }
}];

// Parse CSV from People.ai Query API export
const csvData = $('Fetch Open Opps').first().json.data;

if (!csvData) {
  return [{ json: { opps: [], oppCount: 0, error: 'No CSV data returned' } }];
}

const lines = csvData.split('\n').filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { opps: [], oppCount: 0, error: 'CSV has no data rows' } }];
}

function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && i + 1 < line.length && line[i + 1] === '"') { current += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

const headers = parseCsvLine(lines[0]);
const headerMap = {};
headers.forEach((h, i) => {
  headerMap[h] = i;
  headerMap[h.toLowerCase()] = i;
});

function getField(row, ...names) {
  for (const name of names) {
    const idx = headerMap[name] ?? headerMap[name.toLowerCase()];
    if (idx !== undefined && row[idx] !== undefined && row[idx] !== '') {
      return row[idx];
    }
  }
  return '';
}

const opps = [];
for (let i = 1; i < lines.length; i++) {
  const row = parseCsvLine(lines[i]);
  if (row.length < 2) continue;

  opps.push({
    peopleAiId: getField(row, 'Opportunity ID', 'ootb_opportunity_id', 'ID', 'Id'),
    owners:     getField(row, 'Opportunity Owner (name)', 'Opportunity Owner', 'Opportunity Owners'),
    ownerId:    getField(row, 'Opportunity Owner (id)'),
    name:       getField(row, 'Opportunity Name',    'ootb_opportunity_name'),
    account:    getField(row, 'Account Name',         'ootb_opportunity_account_name'),
    closeDate:  getField(row, 'Close Date',           'ootb_opportunity_close_date'),
    stage:      getField(row, 'Stage',                'ootb_opportunity_current_stage', 'Current Stage'),
    amount:     getField(row, 'Amount (Converted)', 'Converted Amount', 'Amount'),
    crmId:      getField(row, 'Record ID',            'ootb_opportunity_crm_id', 'CRM ID'),
    engagement: getField(row, 'Opportunity Engagement Level', 'ootb_opportunity_engagement_level', 'Engagement Level'),
peopleAiInternalId: getField(row, 'People.ai Internal ID', 'ootb_opportunity_people_internal_id')
  });
}

return [{ json: { opps, oppCount: opps.length, headers } }];

// Filter opportunities for this user based on digest_scope and daily theme
const user         = $input.first().json;
const allOpps      = $('Parse Opps CSV').first().json.opps || [];
const hierarchyData = $('Parse Hierarchy').first().json;

const userEmail  = (user.email || '').toLowerCase().trim();
const digestScope = user.digest_scope || 'my_deals';

// Derive rep name from email (fallback)
const emailLocal = userEmail.split('@')[0] || '';
const repName    = emailLocal.split('.').map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(' ');
const repLower   = repName.toLowerCase();

// Quarter/date helpers
const now = new Date();
const curYear = now.getFullYear();
const curMonth = now.getMonth(); // 0-indexed

function getQuarterEnd(monthsAhead) {
  const target = new Date(now);
  target.setMonth(target.getMonth() + monthsAhead);
  const m = target.getMonth();
  const q = Math.floor(m / 3);
  const qEndMonth = (q + 1) * 3 - 1; // last month of quarter
  const qEndYear  = target.getFullYear();
  return new Date(qEndYear, qEndMonth + 1, 0); // last day of that month
}

const fiscalYearEnd = new Date(curYear, 11, 31);
const twoQtrEnd     = getQuarterEnd(6);

function parseCloseDate(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

function isBefore(d, cutoff) {
  return d && d <= cutoff;
}

// Daily theme (Monday=1 ... Friday=5)
const dayOfWeek = now.getDay();
const themes = {
  1: 'full_pipeline',
  2: 'engagement_shifts',
  3: 'at_risk',
  4: 'momentum',
  5: 'week_review'
};
const theme = themes[dayOfWeek] || 'full_pipeline';

// ── Scope filtering ──────────────────────────────────────────

let userOpps = [];
let scopeLabel = '';
let hierarchyMissing = false;

if (digestScope === 'my_deals') {
  // IC: own deals within fiscal year
  userOpps = allOpps.filter(opp => {
    const owners = (opp.owners || opp.ownerName || opp.owner || '').toLowerCase();
    if (!owners.includes(repLower)) return false;
    const cd = parseCloseDate(opp.closeDate || opp['Close Date'] || opp.close_date);
    return !cd || isBefore(cd, fiscalYearEnd);
  });
  scopeLabel = `${repName}'s Deals`;

} else if (digestScope === 'team_deals') {
  const managerToReports = hierarchyData.managerToReports || {};

  // Collect direct reports — try email key first (most reliable), then name key
  const reportSet = new Map(); // email → {name, email}

  // 1. Direct lookup by manager email (preferred)
  const byEmail = managerToReports[userEmail] || [];
  for (const r of byEmail) {
    if (r.email) reportSet.set(r.email, r);
  }

  // 2. Fuzzy lookup by manager name (fallback)
  for (const [mgrKey, reports] of Object.entries(managerToReports)) {
    if (mgrKey === userEmail) continue; // already handled
    if (mgrKey.includes(repLower) || repLower.includes(mgrKey)) {
      for (const r of reports) {
        if (r.email && !reportSet.has(r.email)) reportSet.set(r.email, r);
      }
    }
  }

  // 3. Infer from hierarchy: find users whose managerEmail === userEmail
  const hierarchyMap = hierarchyData.hierarchy || {};
  for (const [email, info] of Object.entries(hierarchyMap)) {
    const mgrEmail = (info.managerEmail || '').toLowerCase().trim();
    if (mgrEmail === userEmail && !reportSet.has(email)) {
      reportSet.set(email, { name: info.name, email });
    }
  }

  const reportEntries = Array.from(reportSet.values());
  const reportNames   = reportEntries.map(r => (r.name || '').toLowerCase()).filter(Boolean);
  const reportEmails  = reportEntries.map(r => (r.email || '').toLowerCase()).filter(Boolean);

  if (reportEntries.length > 0) {
    // Filter opps by direct report owners
    userOpps = allOpps.filter(opp => {
      const owners     = (opp.owners || opp.ownerName || opp.owner || '').toLowerCase();
      const ownerEmail = (opp.ownerEmail || opp.owner_email || '').toLowerCase();
      const cd = parseCloseDate(opp.closeDate || opp['Close Date'] || opp.close_date);
      if (!isBefore(cd, twoQtrEnd)) return false;
      // Match by email first, then by name
      if (ownerEmail && reportEmails.some(e => ownerEmail.includes(e) || e.includes(ownerEmail))) return true;
      return reportNames.some(n => n && owners.includes(n));
    });
    scopeLabel = `${repName}'s Team Pipeline`;
  } else {
    // Hierarchy unavailable — fall back to top pipeline (all opps, sorted by amount)
    hierarchyMissing = true;
    userOpps = allOpps
      .filter(opp => {
        const cd = parseCloseDate(opp.closeDate || opp['Close Date'] || opp.close_date);
        return isBefore(cd, twoQtrEnd);
      })
      .sort((a, b) => {
        const amtA = parseFloat(String(a.amount || a.Amount || 0).replace(/[$,]/g, '')) || 0;
        const amtB = parseFloat(String(b.amount || b.Amount || 0).replace(/[$,]/g, '')) || 0;
        return amtB - amtA;
      })
      .slice(0, 25);
    scopeLabel = 'Top Pipeline (hierarchy unavailable)';
  }

} else if (digestScope === 'top_pipeline') {
  // Exec: top 25 deals by amount within 2 quarters
  userOpps = allOpps
    .filter(opp => {
      const cd = parseCloseDate(opp.closeDate || opp['Close Date'] || opp.close_date);
      return isBefore(cd, twoQtrEnd);
    })
    .sort((a, b) => {
      const amtA = parseFloat(String(a.amount || a.Amount || 0).replace(/[$,]/g, '')) || 0;
      const amtB = parseFloat(String(b.amount || b.Amount || 0).replace(/[$,]/g, '')) || 0;
      return amtB - amtA;
    })
    .slice(0, 25);
  scopeLabel = 'Top Pipeline';

} else if (digestScope && digestScope.startsWith('person:')) {
  // Custom: specific person's deals
  const targetEmail = digestScope.replace('person:', '').toLowerCase().trim();
  const targetLocal = targetEmail.split('@')[0] || '';
  const targetName  = targetLocal.split('.').map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(' ').toLowerCase();
  userOpps = allOpps.filter(opp => {
    const owners     = (opp.owners || opp.ownerName || opp.owner || '').toLowerCase();
    const ownerEmail = (opp.ownerEmail || opp.owner_email || '').toLowerCase();
    const cd = parseCloseDate(opp.closeDate || opp['Close Date'] || opp.close_date);
    if (!isBefore(cd, fiscalYearEnd)) return false;
    if (ownerEmail && ownerEmail.includes(targetEmail)) return true;
    return owners.includes(targetName);
  });
  scopeLabel = `${targetEmail}'s Deals`;

} else {
  // Default fallback: my_deals
  userOpps = allOpps.filter(opp => {
    const owners = (opp.owners || opp.ownerName || opp.owner || '').toLowerCase();
    return owners.includes(repLower);
  });
  scopeLabel = `${repName}'s Deals`;
}

// ── Theme filtering ──────────────────────────────────────────

let themeNote = '';

if (theme === 'at_risk') {
  const RISK_STAGES = ['discovery', 'qualification', 'needs analysis', 'value proposition'];
  const soonMs = 30 * 24 * 60 * 60 * 1000;
  userOpps = userOpps.filter(opp => {
    const score = parseFloat(opp.engagementScore || opp.engagement_score || opp.score || 100);
    const cd    = parseCloseDate(opp.closeDate || opp['Close Date'] || opp.close_date);
    const stage = (opp.stage || opp.Stage || '').toLowerCase();
    const closingSoon = cd && (cd - now) < soonMs;
    const earlyStage  = RISK_STAGES.some(s => stage.includes(s));
    return score < 40 || (closingSoon && earlyStage);
  });
  themeNote = 'Focused on at-risk deals (low engagement or closing soon in early stage)';
} else if (theme === 'momentum') {
  userOpps = [...userOpps].sort((a, b) => {
    const sA = parseFloat(a.engagementScore || a.engagement_score || a.score || 0);
    const sB = parseFloat(b.engagementScore || b.engagement_score || b.score || 0);
    return sB - sA;
  });
  themeNote = 'Sorted by engagement momentum (highest first)';
}

// ── Build opp table ──────────────────────────────────────────

function fmt(opp) {
  const name   = opp.name || opp.Name || opp.opportunityName || 'Unknown';
  const amount = opp.amount || opp.Amount || '';
  const stage  = opp.stage || opp.Stage || '';
  const close  = opp.closeDate || opp['Close Date'] || opp.close_date || '';
  const owner  = opp.owners || opp.ownerName || opp.owner || '';
  const score  = opp.engagementScore || opp.engagement_score || opp.score || '';
  const crmId  = opp.crmId || opp.CrmId || '';
  const paiId  = opp.peopleAiInternalId || opp.peopleAiId || '';
  return `| ${name} | ${amount} | ${stage} | ${close} | ${owner} | ${score} | ${crmId} | ${paiId} |`;
}

let oppTable = '';
if (userOpps.length > 0) {
  const header = '| Deal | Amount | Stage | Close Date | Owner | Engagement | CRM ID | PAI ID |\n|------|--------|-------|------------|-------|------------|--------|--------|';
  oppTable = header + '\n' + userOpps.slice(0, 30).map(fmt).join('\n');
} else {
  oppTable = '(no deals matched the current filter)';
}

// Hierarchy warning for debugging
const hierarchyWarning = hierarchyMissing
  ? '\n\n⚠️ Note: Manager hierarchy data was not available in the export — showing top pipeline as fallback.'
  : '';

return [{
  json: {
    ...user,
    userOpps,
    userOppCount: userOpps.length,
    scopeLabel,
    themeNote,
    themeLabel: { full_pipeline: 'Brief', engagement_shifts: 'Engagement Shifts', at_risk: 'At-Risk', momentum: 'Momentum', week_review: 'Week in Review' }[theme] || 'Brief',
    dateWindowEnd: twoQtrEnd.toISOString().split('T')[0],
    oppTable: oppTable + hierarchyWarning,
    digestScope,
    theme,
    userEmail,
    repName,
    totalOppCount: allOpps.length,
    reportCount: digestScope === 'team_deals' ? (userOpps.length) : undefined,
    hierarchyMissing: hierarchyMissing || undefined,
  }
}];

// Parse CSV from People.ai User hierarchy export
const csvData = $('Fetch User Hierarchy').first().json.data;

if (!csvData) {
  return [{ json: { hierarchy: {}, managerToReports: {}, userCount: 0, error: 'No hierarchy data returned' } }];
}

const lines = csvData.split('\n').filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { hierarchy: {}, managerToReports: {}, userCount: 0, error: 'Hierarchy CSV has no data rows' } }];
}

function parseCsvLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
}

const headers = parseCsvLine(lines[0]);
const headerMap = {};
headers.forEach((h, i) => { headerMap[h] = i; });

function getField(row, ...names) {
  for (const name of names) {
    if (headerMap[name] !== undefined && row[headerMap[name]]) {
      return row[headerMap[name]];
    }
  }
  return '';
}

const hierarchy = {};
const managerToReports = {};

function addReport(key, report) {
  if (!key) return;
  const k = key.toLowerCase().trim();
  if (!k) return;
  if (!managerToReports[k]) managerToReports[k] = [];
  // Avoid duplicates
  if (!managerToReports[k].some(r => r.email === report.email)) {
    managerToReports[k].push(report);
  }
}

for (let i = 1; i < lines.length; i++) {
  const row = parseCsvLine(lines[i]);
  if (row.length < headers.length) continue;

  const name  = getField(row, 'ootb_user_name', 'User Name', 'Name');
  const email = getField(row, 'ootb_user_email', 'User Email', 'Email').toLowerCase().trim();
  const manager      = getField(row, 'ootb_user_manager', 'Manager', 'User Manager');
  const managerEmail = getField(row, 'ootb_user_manager_email', 'Manager Email', 'User Manager Email').toLowerCase().trim();

  if (email) {
    hierarchy[email] = { name, email, manager, managerEmail };
  }

  // Key by manager email (preferred — exact match, no fuzzy needed)
  if (managerEmail) {
    addReport(managerEmail, { name, email });
  }
  // Key by manager name (fallback for when email isn't available)
  if (manager) {
    addReport(manager, { name, email });
  }
}

return [{ json: { hierarchy, managerToReports, userCount: Object.keys(hierarchy).length } }];

// Gather data for conversation bookend (Sales Digest).
// Runs inside the SplitInBatches loop after Log to Messages.

const identity = $('Resolve Identity').first().json;
const sendResult = $('Send Digest').first().json;
const agentOutput = $('Digest Agent').first().json.output || '';
const filterData = $('Filter User Opps').first().json;

// userId / organizationId: Resolve Identity outputs these but they may be
// undefined because Filter User Opps doesn't spread the original user record.
// Fall back to the Log to Messages Supabase response which echoes user_id.
let userId = identity.userId || null;
let organizationId = null;
try {
  // Log to Messages inserts into messages table — its response has user_id
  const logResp = $('Log to Messages').first().json;
  if (!userId && logResp.user_id) userId = logResp.user_id;
} catch(e) {}

// Channel and thread_ts from the Send Digest Slack response
const channelId = sendResult.channel || '';
const threadTs = sendResult.ts || '';

const agentConfig = {
  model: 'claude-sonnet-4-5-20250929',
  mcpEndpoint: 'https://mcp-canary.people.ai/mcp',
  assistantName: identity.assistantName || 'Aria',
  assistantEmoji: identity.assistantEmoji || ':robot_face:',
  digestScope: identity.digestScope || 'my_deals',
  theme: identity.theme || 'full_pipeline'
};

// Digest conversations expire after 4 hours (not continuable, but recorded)
const expiresAt = new Date(Date.now() + 4 * 60 * 60 * 1000).toISOString();

return [{
  json: {
    organizationId: organizationId,
    userId: userId,
    channelId: channelId,
    threadTs: threadTs,
    workflowType: 'digest',
    agentConfig: agentConfig,
    expiresAt: expiresAt,
    userMessage: 'Daily digest',
    assistantMessage: agentOutput
  }
}];

