// === Shared Block Kit formatting rules ===
const blockKitRules = `OUTPUT FORMAT — CRITICAL:
Respond with ONLY a valid JSON object. Your ENTIRE response must be the JSON object and nothing else. No prose before or after. No explanation. No markdown code fences (no backticks). No "let me" or "here is" preamble. Start your response with { and end with }.

Your response must have exactly this shape:
{
  "notification_text": "string — one sentence, shown in push notifications",
  "blocks": [ array of valid Slack Block Kit blocks ]
}

BLOCK KIT STRUCTURE RULES:
- Use a "header" block for the message title (plain_text only, emoji: true)
- Use "section" blocks with "mrkdwn" text for all body content
- Use "divider" blocks between major sections (maximum 2 per message)
- Use "section" with "fields" for two-column data (engagement scores, metrics)
  - MAXIMUM 10 fields per section block (Slack API hard limit)
  - If you have more than 10 data points, split into multiple section blocks
- Use "context" block at the bottom for timestamp and data source
- Maximum 50 blocks per message

MRKDWN RULES (inside all text fields):
- Bold: *text* — single asterisks only
- Line break: \\n
- Blank line: \\n\\n
- Top-level bullets: use the • character (e.g. • Main point)
- Sub-bullets under a numbered item or heading: indent with 4 spaces before the bullet (e.g.     • Sub-point)
- This creates visual hierarchy — numbered deals at top level, details indented beneath
- NO ## headers — use *bold text* on its own line instead
- NO **double asterisks**
- NO standard markdown links [text](url) — use <https://url|text>
- NO dash bullets (-)

EMOJI STATUS INDICATORS — use these consistently:
🚀 Acceleration / strong momentum
⚠️ Risk pattern detected
💎 Hidden upside opportunity
🔴 Stalled / critical risk
✅ Healthy / on track
📈 Engagement rising
📉 Engagement falling
➡️ Engagement stable
🔥 High engagement (80+)

CRITICAL PRIORITIZATION RULE:
- Always prioritize deals closing in the NEXT 60 DAYS over deals closing later, regardless of deal size
- Today's date context is in the footer — use it to calculate proximity
- A $500K deal closing in 3 weeks matters more RIGHT NOW than a $3M deal closing in 8 months
- For deals closing 60+ days out, only mention them if they need immediate action (e.g., stalled engagement, missing exec sponsor)
- When listing "Top" deals, sort by close date proximity first, then by amount within the same time horizon`;

// === Focus-specific context injected into the system prompt ===
function getFocusContext(focus) {
  if (focus === 'retention') {
    return `FOCUS — RETENTION:
Your briefing covers only renewal and existing customer opportunities. New logo deals are excluded.
Prioritise: renewal health, time-to-renewal, expansion potential, customer engagement trends, churn risk.
Actions should be customer-success oriented: QBR scheduling, exec sponsor engagement, product adoption nudges, risk escalation.
Do NOT suggest new outreach tactics or prospecting actions.`;
  }
  if (focus === 'technical') {
    return `FOCUS — TECHNICAL:
You are briefing through an SE/solutions lens. Highlight POC status, technical blockers, and integration complexity.
Prioritise: deals in evaluation or validation stages, technical win/loss indicators, stakeholder technical depth.
Actions should be SE-oriented: POC milestones, technical champion engagement, competitive technical positioning.`;
  }
  if (focus === 'executive') {
    return `FOCUS — EXECUTIVE:
Deliver a high-altitude strategic view. Skip deal-level minutiae — focus on portfolio health, forecast risk, and org-level patterns.
Prioritise: total ARR at risk, big-bet deals, cross-functional signals, pipeline coverage.
Actions should be executive: sponsorship asks, resource allocation, forecast decisions.`;
  }
  // revenue (default) — no extra constraints
  return `FOCUS — REVENUE:
Prioritise new logo acquisition, net new ARR, and close-date velocity. Highlight deals with near-term close potential.
Actions should drive pipeline forward: next meeting, proposal, executive alignment, competitive positioning.`;
}

